// Calcul du score multicritère (version inline du pipeline scoring.js)
const rows = items.map(i => i.json);
const TOTAL_SERVICES = 11;
const W = { events: 0.30, email: 0.25, services: 0.20, digital: 0.15, dynamique: 0.10 };

function oui(v) { return String(v || '').trim().toLowerCase() === 'oui'; }
function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

return rows.map(r => {
  const nbEvents = Number(r.Nb_Participations_12m || 0);
  const medFiliere = Number(r.Mediane_Filiere || 1);
  const nbServices = Number(r.Nb_Services_Distincts || 0);
  const ancien = Number(r.Score_Engagement || 0);

  const s_events = nbEvents === 0 ? 0 : Math.min(100, (nbEvents / medFiliere) * 100);
  const s_email = oui(r.Email_Optin) ? clamp((ancien / 100) * 0.4, 0, 1) * 100 : 0;
  const s_services = Math.min(100, (nbServices / TOTAL_SERVICES) * 100);
  const s_digital = Math.min(100, (oui(r.App_MyCFCIM) ? 60 : 0) + (oui(r.Email_Optin) ? 40 : 0));

  const partial = (s_events * W.events + s_email * W.email + s_services * W.services + s_digital * W.digital) / 0.9;
  const s_dyn = partial > ancien + 5 ? 100 : partial < ancien - 5 ? 0 : 50;

  const total = Math.round(clamp(
    s_events * W.events + s_email * W.email + s_services * W.services + s_digital * W.digital + s_dyn * W.dynamique,
    0, 100
  ));

  return { json: { ...r, Score_Calcule: total, score_events: Math.round(s_events), score_email: Math.round(s_email), score_services: Math.round(s_services), score_digital: Math.round(s_digital), score_dynamique: s_dyn } };
});

